// ChatMessageModal.jsx - Professional UI + Read Receipts
import React, { useState, useEffect, useRef, useCallback } from "react";
import { X, Send, Check, CheckCheck } from "lucide-react";
import {
    getMessages,
    sendMessage,
    initSocket,
    joinConversation,
    leaveConversation,
    onNewMessage,
    emitTypingStart,
    emitTypingEnd,
    onUserTyping,
    emitMarkAsRead,
    onMessagesRead,
    removeAllListeners,
} from "../../../api/chatApi";
import axios from "axios";
import { API_BASE_URL } from "../../../config/config";

export default function ChatMessageModal({ onClose, currentUser, selectedUser }) {
    const [messages, setMessages] = useState([]);
    const [messageInput, setMessageInput] = useState("");
    const [conversation, setConversation] = useState(null);
    const [loading, setLoading] = useState(false);
    const [otherUserTyping, setOtherUserTyping] = useState(false);
    const messagesEndRef = useRef(null);
    const messagesAreaRef = useRef(null);
    const typingTimeoutRef = useRef(null);
    const conversationRef = useRef(null);
    const observerRef = useRef(null);
    const API_URL = `${API_BASE_URL}api/user/chatmessage`;

    // ── Init ────────────────────────────────────────────────────────────────
    useEffect(() => {
        if (!currentUser?.id || !selectedUser?.id) return;
        initSocket();
        setupConversation();

        return () => {
            if (conversationRef.current) leaveConversation(conversationRef.current);
            removeAllListeners(["new-message", "user-typing", "messages-read"]);
            if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
            if (observerRef.current) observerRef.current.disconnect();
        };
    }, [selectedUser?.id]);

    const setupConversation = async () => {
        setLoading(true);
        try {
            const response = await axios.post(
                `${API_URL}/get_or_create_conversation`,
                {
                    participant1_type: currentUser?.type,
                    participant1_id: currentUser?.id,
                    participant2_type: selectedUser?.type,
                    participant2_id: selectedUser?.id,
                },
                { headers: { "Content-Type": "application/json" } }
            );

            if (response.data.success) {
                const conv = response.data.conversation;
                setConversation(conv);
                conversationRef.current = conv.conversation_id;
                joinConversation(conv.conversation_id);
                emitMarkAsRead(conv.conversation_id, currentUser.id);
                await loadMessages(conv.conversation_id);
                setupSocketListeners();
            }
        } catch (error) {
            console.error("setupConversation error:", error.message);
        } finally {
            setLoading(false);
        }
    };

    const setupSocketListeners = () => {
        onNewMessage((newMsg) => {
            // Normalize ids to numbers (DB returns strings)
            newMsg.sender_id = Number(newMsg.sender_id);
            newMsg.receiver_id = Number(newMsg.receiver_id);

            setMessages((prev) => {
                // Duplicate check by real id
                if (prev.some((m) => m.id === newMsg.id)) return prev;

                // Sender's own message — already replaced by HTTP response, skip
                if (newMsg.sender_id === currentUser.id) {
                    return prev;
                }

                // Receiver gets new message → mark as read (modal is open)
                if (newMsg.receiver_id === currentUser.id) {
                    markMessageRead(newMsg.id);
                    newMsg.is_read = 1;
                }
                return [...prev, newMsg];
            });
            scrollToBottom();
        });

        // Other user read our messages → turn ticks blue
        onMessagesRead((data) => {
            if (data.user_id !== currentUser.id) {
                setMessages((prev) =>
                    prev.map((m) =>
                        m.sender_id === currentUser.id ? { ...m, is_read: 1 } : m
                    )
                );
            }
        });

        onUserTyping((data) => {
            if (data.user_id !== currentUser.id) {
                setOtherUserTyping(data.isTyping);
            }
        });
    };

    const loadMessages = async (conversationId) => {
        try {
            const response = await getMessages(conversationId, currentUser.id, currentUser.type);
            if (response.success) {
                setMessages(response.messages);
                setTimeout(() => {
                    scrollToBottom();
                    setupIntersectionObserver();
                }, 150);
            }
        } catch (err) {
            console.error("loadMessages error:", err);
        }
    };

    // ── Intersection Observer — mark as read on scroll ───────────────────────
    const setupIntersectionObserver = () => {
        if (observerRef.current) observerRef.current.disconnect();
        observerRef.current = new IntersectionObserver(
            (entries) => {
                entries.forEach((entry) => {
                    if (entry.isIntersecting) {
                        const msgId = parseInt(entry.target.dataset.msgid);
                        const senderId = parseInt(entry.target.dataset.senderid);
                        if (senderId !== currentUser.id) {
                            markMessageRead(msgId);
                            setMessages((prev) =>
                                prev.map((m) => (m.id === msgId ? { ...m, is_read: 1 } : m))
                            );
                        }
                    }
                });
            },
            { threshold: 0.8, root: messagesAreaRef.current }
        );
    };

    const observeMessage = useCallback((el) => {
        if (el && observerRef.current) observerRef.current.observe(el);
    }, []);

    const markMessageRead = async (messageId) => {
        if (!messageId || messageId.toString().startsWith("opt_")) return;
        try {
            await axios.post(`${API_URL}/mark-read`, {
                message_id: messageId,
                user_id: currentUser.id,
                user_type: currentUser.type,
            });
            if (conversationRef.current) {
                emitMarkAsRead(conversationRef.current, currentUser.id);
            }
        } catch (err) { /* silent */ }
    };

    // ── Send ─────────────────────────────────────────────────────────────────
    const handleSendMessage = async () => {
        if (!messageInput.trim() || !conversation) return;
        const text = messageInput;
        setMessageInput("");

        const optimisticMsg = {
            id: `opt_${Date.now()}`,
            _optimistic: true,
            message: text,
            sender_id: currentUser.id,
            sender_type: currentUser.type,
            receiver_id: selectedUser.id,
            receiver_type: selectedUser.type,
            conversation_id: conversation.conversation_id,
            created_at: null, // Will be replaced by real DB timestamp from HTTP response
            is_read: 0,
            is_delivered: 0,
        };

        setMessages((prev) => [...prev, optimisticMsg]);
        scrollToBottom();
        if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
        emitTypingEnd(conversation.conversation_id, currentUser.id);

        try {
            const res = await sendMessage(
                conversation.conversation_id,
                currentUser.type, currentUser.id,
                selectedUser.type, selectedUser.id,
                text
            );
            // ✅ Replace optimistic with real DB message
            if (res?.success && res?.message) {
                const realMsg = res.message;
                // Normalize sender_id to number (DB may return string)
                realMsg.sender_id = Number(realMsg.sender_id);
                realMsg.receiver_id = Number(realMsg.receiver_id);
                setMessages((prev) =>
                    prev.map((m) => m.id === optimisticMsg.id ? realMsg : m)
                );
            }
        } catch (err) {
            setMessages((prev) => prev.filter((m) => m.id !== optimisticMsg.id));
        }
    };

    const handleInputChange = (e) => {
        setMessageInput(e.target.value);
        if (!conversation) return;
        emitTypingStart(conversation.conversation_id, currentUser.id, currentUser.name);
        if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
        typingTimeoutRef.current = setTimeout(() => {
            emitTypingEnd(conversation.conversation_id, currentUser.id);
        }, 1500);
    };

    const handleKeyPress = (e) => {
        if (e.key === "Enter" && !e.shiftKey) {
            e.preventDefault();
            handleSendMessage();
        }
    };

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    // ── Helpers ──────────────────────────────────────────────────────────────
    // MySQL "2024-01-12 14:30:00" has no timezone — browser treats as LOCAL, but it is UTC
    // parseTimestamp appends Z to force UTC interpretation
    const parseTimestamp = (ts) => {
        if (!ts) return new Date();
        // Already a Date object (mysql2 returns Date objects for TIMESTAMP columns)
        if (ts instanceof Date) return ts;
        const s = ts.toString().trim();
        // ISO string with Z or offset — parse directly
        if (s.includes("Z") || s.match(/[+-]\d{2}:\d{2}$/)) return new Date(s);
        // MySQL "2024-01-12 14:30:00" — no timezone, treat as UTC
        return new Date(s.replace(" ", "T") + "Z");
    };

    const formatMessageTime = (timestamp) => {
        if (!timestamp) return "sending...";
        const msgDate = parseTimestamp(timestamp);
        const now = new Date();
        const msgDay = new Date(msgDate.getFullYear(), msgDate.getMonth(), msgDate.getDate());
        const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
        const diffDays = Math.round((today - msgDay) / (1000 * 60 * 60 * 24));
        const timeStr = msgDate.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit", hour12: true });
        if (diffDays === 0) return timeStr;
        if (diffDays === 1) return `Yesterday ${timeStr}`;
        if (diffDays < 7) return `${msgDate.toLocaleDateString([], { weekday: "short" })} ${timeStr}`;
        return `${msgDate.toLocaleDateString([], { day: "2-digit", month: "short", year: "numeric" })} ${timeStr}`;
    };

    const getDateLabel = (timestamp) => {
        if (!timestamp) return "";
        const msgDate = parseTimestamp(timestamp);
        const now = new Date();
        const msgDay = new Date(msgDate.getFullYear(), msgDate.getMonth(), msgDate.getDate());
        const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
        const diffDays = Math.round((today - msgDay) / (1000 * 60 * 60 * 24));
        if (diffDays === 0) return "Today";
        if (diffDays === 1) return "Yesterday";
        if (diffDays < 7) return msgDate.toLocaleDateString([], { weekday: "long" });
        return msgDate.toLocaleDateString([], { day: "2-digit", month: "long", year: "numeric" });
    };

    const getRoleColor = (role) => {
        if (role === "company") return "#ff3e43";
        if (role === "investor") return "#22c55e";
        if (role === "admin") return "#9c27b0";
        return "#6c757d";
    };

    const TickIcon = ({ msg }) => {
        if (msg._optimistic) return <Check size={11} color="rgba(255,255,255,0.45)" />;
        if (msg.is_read === 1) return <CheckCheck size={11} color="#4fc3f7" />;  // blue = read
        if (msg.is_delivered) return <CheckCheck size={11} color="rgba(255,255,255,0.55)" />; // grey double
        return <Check size={11} color="rgba(255,255,255,0.55)" />; // grey single = sent
    };

    // ── Render ───────────────────────────────────────────────────────────────
    return (
        <>
            <style>{`
                @keyframes typingBlink {
                    0%,80%,100%{opacity:.25;transform:scale(.85)}
                    40%{opacity:1;transform:scale(1.15)}
                }
                @keyframes fadeSlideIn {
                    from{opacity:0;transform:translateY(6px)}
                    to{opacity:1;transform:translateY(0)}
                }
                .cm-typing-dot{display:inline-block;width:7px;height:7px;border-radius:50%;background:#bcc4ce;animation:typingBlink 1.4s infinite both;margin:0 2px}
                .cm-typing-dot:nth-child(2){animation-delay:.2s}
                .cm-typing-dot:nth-child(3){animation-delay:.4s}
                .cm-input:focus{border-color:#ff3e43!important;box-shadow:0 0 0 3px rgba(255,62,67,.1)!important;background:#fff!important}
                .cm-send:hover:not(:disabled){transform:scale(1.08);box-shadow:0 4px 14px rgba(255,62,67,.45)!important}
                .cm-close:hover{background:#f3f4f6!important}
                .cm-body::-webkit-scrollbar{width:3px}
                .cm-body::-webkit-scrollbar-track{background:transparent}
                .cm-body::-webkit-scrollbar-thumb{background:#dde1e7;border-radius:2px}
                .cm-bubble-in{animation:fadeSlideIn .18s ease}
            `}</style>

            <div style={S.overlay}>
                <div style={S.modal}>

                    {/* Header */}
                    <div style={S.header}>
                        <div style={S.headerLeft}>
                            <div style={S.avatar}>
                                {selectedUser?.name?.charAt(0)?.toUpperCase() || "U"}
                                <span style={S.onlineDot} />
                            </div>
                            <div>
                                <div style={S.headerName}>{selectedUser?.name}</div>
                                <span style={{ ...S.badge, background: getRoleColor(selectedUser?.type) }}>
                                    {selectedUser?.role || selectedUser?.type}
                                </span>
                            </div>
                        </div>
                        <button className="cm-close" onClick={onClose} style={S.closeBtn}>
                            <X size={17} color="#9ca3af" />
                        </button>
                    </div>

                    {/* Messages */}
                    <div className="cm-body" ref={messagesAreaRef} style={S.body}>
                        {loading ? (
                            <div style={S.centerBox}>
                                <div style={S.spinner} />
                                <span style={{ color: "#b0b8c4", fontSize: 13, marginTop: 10 }}>Loading…</span>
                            </div>
                        ) : messages.length === 0 ? (
                            <div style={S.centerBox}>
                                <div style={S.emptyEmoji}>💬</div>
                                <div style={S.emptyTitle}>No messages yet</div>
                                <div style={S.emptySub}>Say hello to {selectedUser?.name}!</div>
                            </div>
                        ) : (
                            messages.map((msg, idx) => {
                                const isMe = msg.sender_id === currentUser?.id;
                                const prevMsg = messages[idx - 1];
                                const showDateSep = !prevMsg ||
                                    getDateLabel(msg.created_at) !== getDateLabel(prevMsg.created_at);

                                return (
                                    <React.Fragment key={msg.id || idx}>
                                        {showDateSep && (
                                            <div style={S.dateSep}>
                                                <span style={S.dateSepText}>{getDateLabel(msg.created_at)}</span>
                                            </div>
                                        )}
                                        <div
                                            className="cm-bubble-in"
                                            ref={!isMe ? observeMessage : null}
                                            data-msgid={msg.id}
                                            data-senderid={msg.sender_id}
                                            style={{ ...S.row, justifyContent: isMe ? "flex-end" : "flex-start" }}
                                        >
                                            {!isMe && (
                                                <div style={S.miniAvatar}>
                                                    {selectedUser?.name?.charAt(0)?.toUpperCase()}
                                                </div>
                                            )}
                                            <div style={{
                                                ...S.bubble,
                                                ...(isMe ? S.bubbleMe : S.bubbleThem),
                                                opacity: msg._optimistic ? 0.72 : 1,
                                            }}>
                                                <p style={S.msgText}>{msg.message}</p>
                                                <div style={S.msgMeta}>
                                                    <span style={{
                                                        ...S.msgTime,
                                                        color: isMe ? "rgba(255,255,255,.6)" : "#b0b8c4"
                                                    }}>
                                                        {formatMessageTime(msg.created_at)}
                                                    </span>
                                                    {isMe && (
                                                        <span style={{ display: "flex", alignItems: "center", marginLeft: 3 }}>
                                                            <TickIcon msg={msg} />
                                                        </span>
                                                    )}
                                                </div>
                                            </div>
                                        </div>
                                    </React.Fragment>
                                );
                            })
                        )}

                        {/* Typing */}
                        {otherUserTyping && (
                            <div style={{ ...S.row, justifyContent: "flex-start" }}>
                                <div style={S.miniAvatar}>{selectedUser?.name?.charAt(0)?.toUpperCase()}</div>
                                <div style={{ ...S.bubble, ...S.bubbleThem, padding: "10px 14px", display: "flex", alignItems: "center" }}>
                                    <span className="cm-typing-dot" />
                                    <span className="cm-typing-dot" />
                                    <span className="cm-typing-dot" />
                                </div>
                            </div>
                        )}
                        <div ref={messagesEndRef} />
                    </div>

                    {/* Footer */}
                    <div style={S.footer}>
                        <input
                            className="cm-input"
                            type="text"
                            placeholder={`Message ${selectedUser?.name}…`}
                            value={messageInput}
                            onChange={handleInputChange}
                            onKeyPress={handleKeyPress}
                            style={S.input}
                        />
                        <button
                            className="cm-send"
                            onClick={handleSendMessage}
                            disabled={!messageInput.trim()}
                            style={{
                                ...S.sendBtn,
                                opacity: !messageInput.trim() ? 0.4 : 1,
                                cursor: !messageInput.trim() ? "not-allowed" : "pointer",
                            }}
                        >
                            <Send size={15} color="#fff" />
                        </button>
                    </div>
                </div>
            </div>
        </>
    );
}

const S = {
    overlay: {
        position: "fixed", inset: 0,
        background: "rgba(10,15,25,.6)",
        zIndex: 99999,
        display: "flex", alignItems: "center", justifyContent: "center",
        backdropFilter: "blur(8px)", padding: 16,
    },
    modal: {
        width: "100%", maxWidth: 460,
        height: "min(660px,90vh)",
        background: "#fff", borderRadius: 22,
        display: "flex", flexDirection: "column", overflow: "hidden",
        boxShadow: "0 28px 80px rgba(0,0,0,.2), 0 0 0 1px rgba(0,0,0,.06)",
    },
    header: {
        padding: "13px 16px",
        borderBottom: "1px solid #f1f3f6",
        display: "flex", justifyContent: "space-between", alignItems: "center",
        background: "#fff",
    },
    headerLeft: { display: "flex", alignItems: "center", gap: 11 },
    avatar: {
        width: 42, height: 42, borderRadius: "50%", position: "relative", flexShrink: 0,
        background: "linear-gradient(135deg,#ff3e43,#ff7070)",
        color: "#fff", display: "flex", alignItems: "center", justifyContent: "center",
        fontWeight: 700, fontSize: 16,
        boxShadow: "0 2px 8px rgba(255,62,67,.28)",
    },
    onlineDot: {
        position: "absolute", bottom: 1, right: 1,
        width: 10, height: 10, borderRadius: "50%",
        background: "#22c55e", border: "2px solid #fff",
    },
    headerName: { fontSize: 14, fontWeight: 650, color: "#111827", letterSpacing: "-.01em" },
    badge: {
        fontSize: 10, padding: "2px 8px", borderRadius: 20,
        color: "#fff", fontWeight: 500, display: "inline-block", marginTop: 2,
        letterSpacing: ".02em",
    },
    closeBtn: {
        background: "none", border: "none", cursor: "pointer",
        width: 32, height: 32, borderRadius: "50%",
        display: "flex", alignItems: "center", justifyContent: "center",
        transition: "background .15s",
    },
    body: {
        flex: 1, overflowY: "auto",
        padding: "14px 14px 8px",
        display: "flex", flexDirection: "column", gap: 1,
        background: "#f6f7fb",
    },
    centerBox: {
        flex: 1, display: "flex", flexDirection: "column",
        alignItems: "center", justifyContent: "center", gap: 6, padding: 40,
    },
    spinner: {
        width: 26, height: 26, borderRadius: "50%",
        border: "3px solid #eef0f4", borderTopColor: "#ff3e43",
        animation: "spin .75s linear infinite",
    },
    emptyEmoji: { fontSize: 38, marginBottom: 2 },
    emptyTitle: { fontSize: 14, fontWeight: 600, color: "#6b7280" },
    emptySub: { fontSize: 12, color: "#b0b8c4" },
    dateSep: {
        display: "flex", alignItems: "center", justifyContent: "center",
        margin: "14px 0 6px",
    },
    dateSepText: {
        fontSize: 11, color: "#8a95a3",
        background: "#eaecf1", padding: "3px 13px",
        borderRadius: 20, fontWeight: 500,
    },
    row: { display: "flex", alignItems: "flex-end", gap: 7, marginBottom: 4 },
    miniAvatar: {
        width: 24, height: 24, borderRadius: "50%", flexShrink: 0,
        background: "linear-gradient(135deg,#6366f1,#8b5cf6)",
        color: "#fff", fontSize: 10, fontWeight: 700,
        display: "flex", alignItems: "center", justifyContent: "center",
    },
    bubble: {
        maxWidth: "72%", padding: "9px 12px",
        borderRadius: 16, wordBreak: "break-word",
        boxShadow: "0 1px 2px rgba(0,0,0,.06)",
    },
    bubbleMe: {
        background: "linear-gradient(135deg,#ff3e43,#ff6565)",
        color: "#fff", borderBottomRightRadius: 4,
    },
    bubbleThem: {
        background: "#fff", color: "#1f2937",
        borderBottomLeftRadius: 4,
        border: "1px solid #eef0f4",
    },
    msgText: { margin: 0, fontSize: 14, lineHeight: 1.5 },
    msgMeta: {
        display: "flex", alignItems: "center", justifyContent: "flex-end",
        gap: 2, marginTop: 4,
    },
    msgTime: { fontSize: 10, lineHeight: 1 },
    footer: {
        padding: "11px 14px",
        borderTop: "1px solid #f1f3f6",
        display: "flex", gap: 9, alignItems: "center",
        background: "#fff",
    },
    input: {
        flex: 1, padding: "10px 16px",
        border: "1.5px solid #eef0f4", borderRadius: 24,
        outline: "none", fontSize: 14, color: "#111827",
        background: "#f6f7fb",
        transition: "border-color .2s,box-shadow .2s,background .2s",
    },
    sendBtn: {
        width: 38, height: 38, borderRadius: "50%",
        background: "linear-gradient(135deg,#ff3e43,#ff6565)",
        border: "none", flexShrink: 0,
        display: "flex", alignItems: "center", justifyContent: "center",
        boxShadow: "0 2px 8px rgba(255,62,67,.3)",
        transition: "transform .15s,box-shadow .15s",
    },
};